import{_ as l,o as r,c as i,ai as e}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"缓存系统","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/database/caching.md","filePath":"tech-system/database/caching.md"}'),n={name:"tech-system/database/caching.md"};function t(s,a,o,h,g,d){return r(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="缓存系统" tabindex="-1">缓存系统 <a class="header-anchor" href="#缓存系统" aria-label="Permalink to “缓存系统”">​</a></h1><p>缓存系统通过在访问速度快的存储中保存常用数据，大幅提升系统性能和用户体验。是构建高并发、低延迟系统的关键技术。</p><h2 id="缓存原理" tabindex="-1">缓存原理 <a class="header-anchor" href="#缓存原理" aria-label="Permalink to “缓存原理”">​</a></h2><h3 id="缓存作用" tabindex="-1">缓存作用 <a class="header-anchor" href="#缓存作用" aria-label="Permalink to “缓存作用”">​</a></h3><ul><li><strong>性能提升</strong>: 减少数据库查询、降低延迟、提高吞吐</li><li><strong>成本降低</strong>: 减少数据库压力、降低 I/O 消耗</li><li><strong>可用性</strong>: 容错能力、数据预热、快速响应</li></ul><h3 id="缓存流程" tabindex="-1">缓存流程 <a class="header-anchor" href="#缓存流程" aria-label="Permalink to “缓存流程”">​</a></h3><ol><li>检查缓存中是否存在数据</li><li>如果存在，直接返回（缓存命中）</li><li>如果不存在，查询数据源（缓存缺失）</li><li>写入缓存并返回</li></ol><h3 id="评价指标" tabindex="-1">评价指标 <a class="header-anchor" href="#评价指标" aria-label="Permalink to “评价指标”">​</a></h3><ul><li><strong>命中率</strong>: 缓存命中次数 / 总查询次数</li><li><strong>延迟</strong>: 平均响应时间、P99 响应时间</li><li><strong>容量</strong>: 可存储数据量、成本</li><li><strong>淘汰率</strong>: 缓存溢出频率、热数据保留</li></ul><h2 id="缓存分层" tabindex="-1">缓存分层 <a class="header-anchor" href="#缓存分层" aria-label="Permalink to “缓存分层”">​</a></h2><h3 id="l1-本地缓存" tabindex="-1">L1：本地缓存 <a class="header-anchor" href="#l1-本地缓存" aria-label="Permalink to “L1：本地缓存”">​</a></h3><ul><li><strong>内存缓存</strong>: 应用进程内、访问最快、容量有限</li><li><strong>工具</strong>: GuavaCache、Caffeine、节点本地</li><li><strong>特点</strong>: 进程隔离、无网络开销、热数据优先</li></ul><h3 id="l2-分布式缓存" tabindex="-1">L2：分布式缓存 <a class="header-anchor" href="#l2-分布式缓存" aria-label="Permalink to “L2：分布式缓存”">​</a></h3><ul><li><strong>Redis</strong>: 内存存储、持久化、丰富数据结构、高性能</li><li><strong>Memcached</strong>: 简单键值、内存存储、高并发</li><li><strong>特点</strong>: 跨进程、网络通信、全局缓存</li></ul><h3 id="l3-磁盘缓存" tabindex="-1">L3：磁盘缓存 <a class="header-anchor" href="#l3-磁盘缓存" aria-label="Permalink to “L3：磁盘缓存”">​</a></h3><ul><li><strong>数据库缓存</strong>: MySQL Query Cache、InnoDB Buffer Pool</li><li><strong>HTTP 缓存</strong>: CDN、反向代理缓存</li><li><strong>特点</strong>: 容量大、访问慢、持久化</li></ul><h2 id="redis-缓存" tabindex="-1">Redis 缓存 <a class="header-anchor" href="#redis-缓存" aria-label="Permalink to “Redis 缓存”">​</a></h2><h3 id="数据结构" tabindex="-1">数据结构 <a class="header-anchor" href="#数据结构" aria-label="Permalink to “数据结构”">​</a></h3><ul><li><strong>String</strong>: 计数、缓存对象、位操作</li><li><strong>Hash</strong>: 缓存对象、字段级别访问、内存高效</li><li><strong>List</strong>: 队列、最新数据、消息队列</li><li><strong>Set</strong>: 标签、用户交集、去重计数</li><li><strong>Sorted Set</strong>: 排行榜、时间序列、范围查询</li></ul><h3 id="过期策略" tabindex="-1">过期策略 <a class="header-anchor" href="#过期策略" aria-label="Permalink to “过期策略”">​</a></h3><ul><li><strong>TTL</strong>: 设置过期时间、自动删除、内存管理</li><li><strong>惰性删除</strong>: 访问时检查、减少内存开销</li><li><strong>主动删除</strong>: 定期清理、及时回收、内存稳定</li></ul><h3 id="淘汰策略" tabindex="-1">淘汰策略 <a class="header-anchor" href="#淘汰策略" aria-label="Permalink to “淘汰策略”">​</a></h3><ul><li><strong>LRU</strong>: Least Recently Used、访问时间优先</li><li><strong>LFU</strong>: Least Frequently Used、访问频率优先</li><li><strong>随机删除</strong>: Random Eviction、简单高效</li><li><strong>不淘汰</strong>: NoEviction、报错处理、强制性</li></ul><h2 id="缓存策略" tabindex="-1">缓存策略 <a class="header-anchor" href="#缓存策略" aria-label="Permalink to “缓存策略”">​</a></h2><h3 id="cache-aside" tabindex="-1">Cache-Aside <a class="header-anchor" href="#cache-aside" aria-label="Permalink to “Cache-Aside”">​</a></h3><ul><li><strong>读流程</strong>: 查询缓存 → 不存在查源 → 写入缓存</li><li><strong>写流程</strong>: 更新源 → 删除缓存（或更新）</li><li><strong>特点</strong>: 简单常用、缓存和源分离、更新灵活</li><li><strong>缺点</strong>: 初始化慢、缓存缺失多</li></ul><h3 id="write-through" tabindex="-1">Write-Through <a class="header-anchor" href="#write-through" aria-label="Permalink to “Write-Through”">​</a></h3><ul><li><strong>写流程</strong>: 同时更新缓存和源、保证一致性</li><li><strong>读流程</strong>: 从缓存读取、不存在再查源</li><li><strong>特点</strong>: 一致性强、写操作成本高</li><li><strong>缺点</strong>: 写入延迟、假设目标可用性</li></ul><h3 id="write-behind" tabindex="-1">Write-Behind <a class="header-anchor" href="#write-behind" aria-label="Permalink to “Write-Behind”">​</a></h3><ul><li><strong>写流程</strong>: 先写缓存、异步写源</li><li><strong>优点</strong>: 写入快、性能优秀</li><li><strong>缺点</strong>: 缓存故障可能丢数据、一致性弱</li></ul><h2 id="缓存一致性" tabindex="-1">缓存一致性 <a class="header-anchor" href="#缓存一致性" aria-label="Permalink to “缓存一致性”">​</a></h2><h3 id="缓存失效" tabindex="-1">缓存失效 <a class="header-anchor" href="#缓存失效" aria-label="Permalink to “缓存失效”">​</a></h3><ul><li><strong>主动失效</strong>: 更新时立即失效、简单但覆盖面宽</li><li><strong>延迟失效</strong>: 设置合理 TTL、定期刷新</li><li><strong>版本控制</strong>: 版本号变化、缓存 key 变化、平滑过渡</li></ul><h3 id="缓存预热" tabindex="-1">缓存预热 <a class="header-anchor" href="#缓存预热" aria-label="Permalink to “缓存预热”">​</a></h3><ul><li><strong>启动预热</strong>: 应用启动时加载常用数据</li><li><strong>定期预热</strong>: 正常运行时更新热数据</li><li><strong>工具</strong>: 计划任务、异步加载、主动刷新</li></ul><h3 id="缓存穿透、击穿、雪崩" tabindex="-1">缓存穿透、击穿、雪崩 <a class="header-anchor" href="#缓存穿透、击穿、雪崩" aria-label="Permalink to “缓存穿透、击穿、雪崩”">​</a></h3><p><strong>缓存穿透</strong>：访问不存在的数据，每次都查询源</p><ul><li>解决：布隆过滤、空值缓存、参数校验</li></ul><p><strong>缓存击穿</strong>：热键失效，大量请求查询源</p><ul><li>解决：分布式锁、互斥锁、热键监控</li></ul><p><strong>缓存雪崩</strong>：大量缓存同时失效，源压力过大</p><ul><li>解决：过期时间分散、缓存预热、流量限制</li></ul><h2 id="缓存框架" tabindex="-1">缓存框架 <a class="header-anchor" href="#缓存框架" aria-label="Permalink to “缓存框架”">​</a></h2><h3 id="caffeine" tabindex="-1">Caffeine <a class="header-anchor" href="#caffeine" aria-label="Permalink to “Caffeine”">​</a></h3><ul><li><strong>特性</strong>: 高性能本地缓存、自动驱逐、TTL/Size 控制</li><li><strong>API</strong>: 简洁易用、Lambda 支持</li><li><strong>性能</strong>: 并发处理、原子操作、吞吐量高</li></ul><h3 id="分布式缓存框架" tabindex="-1">分布式缓存框架 <a class="header-anchor" href="#分布式缓存框架" aria-label="Permalink to “分布式缓存框架”">​</a></h3><ul><li><strong>Spring Cache</strong>: 注解驱动、透明集成</li><li><strong>Hazelcast</strong>: 内存数据网格、分布式结构</li><li><strong>Ignite</strong>: 分布式计算、缓存一体化</li></ul><h2 id="缓存问题排查" tabindex="-1">缓存问题排查 <a class="header-anchor" href="#缓存问题排查" aria-label="Permalink to “缓存问题排查”">​</a></h2><h3 id="高缓存命中同时性能仍差" tabindex="-1">高缓存命中同时性能仍差 <a class="header-anchor" href="#高缓存命中同时性能仍差" aria-label="Permalink to “高缓存命中同时性能仍差”">​</a></h3><ul><li>原因：网络延迟、反序列化、GC 停顿</li><li>解决：优化网络、压缩数据、GC 优化</li></ul><h3 id="缓存数据不一致" tabindex="-1">缓存数据不一致 <a class="header-anchor" href="#缓存数据不一致" aria-label="Permalink to “缓存数据不一致”">​</a></h3><ul><li>原因：更新逻辑错误、并发竞态、网络延迟</li><li>解决：加锁、版本控制、延迟更新</li></ul><h3 id="内存持续增长" tabindex="-1">内存持续增长 <a class="header-anchor" href="#内存持续增长" aria-label="Permalink to “内存持续增长”">​</a></h3><ul><li>原因：缓存淘汰失效、内存泄漏、没有过期</li><li>解决：检查配置、监控内存、定期清理</li></ul><h2 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to “性能优化”">​</a></h2><h3 id="缓存读写" tabindex="-1">缓存读写 <a class="header-anchor" href="#缓存读写" aria-label="Permalink to “缓存读写”">​</a></h3><ul><li><strong>批量读取</strong>: 减少网络往返、提高吞吐</li><li><strong>管道化</strong>: Pipeline 批量命令、减少延迟</li><li><strong>异步访问</strong>: 异步加载、不阻塞主线程</li></ul><h3 id="数据序列化" tabindex="-1">数据序列化 <a class="header-anchor" href="#数据序列化" aria-label="Permalink to “数据序列化”">​</a></h3><ul><li><strong>序列化格式</strong>: JSON vs 二进制、体积 vs 速度</li><li><strong>压缩</strong>: GZIP、Snappy、减少网络传输</li><li><strong>字段优化</strong>: 只缓存必要字段、定期更新</li></ul><h3 id="缓存预热-1" tabindex="-1">缓存预热 <a class="header-anchor" href="#缓存预热-1" aria-label="Permalink to “缓存预热”">​</a></h3><ul><li><strong>启动预热</strong>: 快速暖缓存、减少初始延迟</li><li><strong>智能预热</strong>: 预测热咨询、机器学习应用</li><li><strong>CDN 预热</strong>: 边缘节点分发、地理分布</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="缓存设计" tabindex="-1">缓存设计 <a class="header-anchor" href="#缓存设计" aria-label="Permalink to “缓存设计”">​</a></h3><ul><li><strong>合理 TTL</strong>: 业务可接受的不一致程度</li><li><strong>缓存 key 设计</strong>: 可读性、版本隔离、容易管理</li><li><strong>缓存预案</strong>: 降级策略、故障应对、监控告警</li></ul><h3 id="监控指标" tabindex="-1">监控指标 <a class="header-anchor" href="#监控指标" aria-label="Permalink to “监控指标”">​</a></h3><ul><li><strong>命中率</strong>: &gt; 80% 为合理、持续上升为目标</li><li><strong>延迟</strong>: P99 &lt; 50ms (本地) / P99 &lt; 200ms (远程)</li><li><strong>容量</strong>: 监控使用率、定期扩容、成本规划</li></ul><h3 id="运维管理" tabindex="-1">运维管理 <a class="header-anchor" href="#运维管理" aria-label="Permalink to “运维管理”">​</a></h3><ul><li><strong>备份恢复</strong>: RDB/AOF 持久化、冷启动数据</li><li><strong>故障处理</strong>: 缓存故障转移、自动降级</li><li><strong>版本升级</strong>: 滚动升级、零停机、兼容性验证</li></ul>',68)])])}const u=l(n,[["render",t]]);export{b as __pageData,u as default};
